// ═══════════════════════════════════════════════════════════════
// KONFIGURATION
// ═══════════════════════════════════════════════════════════════

const SEND_EXISTING_ON_FIRST_RUN = false;
// true  → send ALLE eksisterende ved første kørsel + nye fremadrettet
// false → ignorer eksisterende, send KUN nye fremadrettet (default)

// ═══════════════════════════════════════════════════════════════

const staticData = $getWorkflowStaticData('global');
const seenIds = new Set(staticData.seenIds || []);

// Auto-detect data path fra GraphQL response
const dataObj = $input.first().json.data;
const dataKey = Object.keys(dataObj).find(k => dataObj[k]?.data && Array.isArray(dataObj[k].data));
if (!dataKey) throw new Error('Kunne ikke finde data-array i GraphQL response.');

const allItems = dataObj[dataKey].data;

// Find nye items (ukendte IDs)
const newItems = allItems.filter(item => !seenIds.has(item.id));

// Opdater static data med nye IDs
staticData.seenIds = [...seenIds, ...newItems.map(item => item.id)];

// Første kørsel
if (!staticData.initialized) {
  staticData.initialized = true;
  if (!SEND_EXISTING_ON_FIRST_RUN) {
    return []; // Stop stille - ingen mail sendes
  }
  // SEND_EXISTING_ON_FIRST_RUN = true: fortsæt - alle newItems er "nye"
}

// Ingen nye poster - stop stille
if (newItems.length === 0) {
  return [];
}

// ═══════════════════════════════════════════════════════════════
// TILPAS: Byg HTML tabel ud fra de felter der er relevante
// ═══════════════════════════════════════════════════════════════

const rows = newItems.map(item => `
  <tr>
    <td style="padding:8px;border:1px solid #ddd;">${item.id}</td>
  </tr>
`).join('');

const html = `
<p>${newItems.length} nye poster fundet:</p>
<table style="border-collapse:collapse;font-family:sans-serif;font-size:14px;width:100%;">
  <thead>
    <tr style="background:#15847F;color:white;">
      <th style="padding:8px;text-align:left;">ID</th>
    </tr>
  </thead>
  <tbody>${rows}</tbody>
</table>
`;

return [{ json: { html, count: newItems.length } }];
